   280→               public Http::StreamFilter,
   281→               public Filters::Common::ExtAuthz::RequestCallbacks {
   282→public:
   283→  Filter(const FilterConfigSharedPtr& config, Filters::Common::ExtAuthz::ClientPtr&& client)
   284→      : config_(config), client_(std::move(client)), stats_(config->stats()) {}
   285→
   286→  // Http::StreamFilterBase
