   288→
   289→  // Http::StreamDecoderFilter
   290→  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers,
   291→                                          bool end_stream) override;
   292→  Http::FilterDataStatus decodeData(Buffer::Instance& data, bool end_stream) override;
   293→  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap& trailers) override;
   294→  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;
   295→
   296→  // Http::StreamEncoderFilter
   297→  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap& headers) override;
   298→  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers,
   299→                                          bool end_stream) override;
   300→  Http::FilterDataStatus encodeData(Buffer::Instance& data, bool end_stream) override;
   301→  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap& trailers) override;
   302→  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap& trailers) override;
   303→  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;
   304→
   305→  // ExtAuthz::RequestCallbacks
   306→  void onComplete(Filters::Common::ExtAuthz::ResponsePtr&&) override;
   307→
   308→private:
   309→  // Convenience function for the following:
   310→  // 1. If `validate_mutations` is set to true, validate header key and value.
   311→  // 2. If `decoder_header_mutation_rules` is set, check that mutation is allowed.
   312→  Filters::Common::MutationRules::CheckResult
   313→  validateAndCheckDecoderHeaderMutation(Filters::Common::MutationRules::CheckOperation operation,
   314→                                        absl::string_view key, absl::string_view value) const;
   315→
   316→  // Called when the filter is configured to reject invalid responses & the authz response contains
   317→  // invalid header or query parameters. Sends a local response with the configured rejection status
   318→  // code.
   319→  void rejectResponse();
   320→
   321→  absl::optional<MonotonicTime> start_time_;
   322→  void addResponseHeaders(Http::HeaderMap& header_map, const Http::HeaderVector& headers);
   323→  void initiateCall(const Http::RequestHeaderMap& headers);
   324→  void continueDecoding();
   325→  bool isBufferFull(uint64_t num_bytes_processing) const;
   326→
   327→  // This holds a set of flags defined in per-route configuration.
   328→  struct PerRouteFlags {
   329→    const bool skip_check_;
   330→    const envoy::extensions::filters::http::ext_authz::v3::CheckSettings check_settings_;
   331→  };
   332→  PerRouteFlags getPerRouteFlags(const Router::RouteConstSharedPtr& route) const;
   333→
   334→  // State of this filter's communication with the external authorization service.
   335→  // The filter has either not started calling the external service, in the middle of calling
   336→  // it or has completed.
   337→  enum class State { NotStarted, Calling, Complete };
   338→
   339→  // FilterReturn is used to capture what the return code should be to the filter chain.
   340→  // if this filter is either in the middle of calling the service or the result is denied then
   341→  // the filter chain should stop. Otherwise, the filter chain can continue to the next filter.
   342→  enum class FilterReturn { ContinueDecoding, StopDecoding };
   343→
   344→  Http::HeaderMapPtr getHeaderMap(const Filters::Common::ExtAuthz::ResponsePtr& response);
   345→  FilterConfigSharedPtr config_;
   346→  Filters::Common::ExtAuthz::ClientPtr client_;
   347→  Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
   348→  Http::StreamEncoderFilterCallbacks* encoder_callbacks_{};
   349→  Http::RequestHeaderMap* request_headers_;
   350→  Http::HeaderVector response_headers_to_add_{};
   351→  Http::HeaderVector response_headers_to_set_{};
   352→  Http::HeaderVector response_headers_to_add_if_absent_{};
   353→  Http::HeaderVector response_headers_to_overwrite_if_exists_{};
   354→  State state_{State::NotStarted};
   355→  FilterReturn filter_return_{FilterReturn::ContinueDecoding};
   356→  Upstream::ClusterInfoConstSharedPtr cluster_;
   357→  // The stats for the filter.
   358→  ExtAuthzFilterStats stats_;
   359→
