   149→            Grpc::Utility::grpcStatusToString(status));
   150→  ASSERT(status != Grpc::Status::WellKnownGrpcStatus::Ok);
   151→  Response response{};
   152→  response.status = CheckStatus::Error;
   153→  response.status_code = Http::Code::Forbidden;
   154→  callbacks_->onComplete(std::make_unique<Response>(response));
   155→  callbacks_ = nullptr;
   156→}
